$ErrorActionPreference = "Stop"

Write-Host ""
Write-Host "=== INSTALADOR FINANCEIRO ORCALY V2 ===" -ForegroundColor Cyan
Write-Host ""

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path -LiteralPath $project)) {
  Write-Host "Projeto nao encontrado em: $project" -ForegroundColor Red
  Write-Host "Abra o PowerShell dentro da pasta do projeto ou edite a variavel `$project no script." -ForegroundColor Yellow
  exit 1
}

Set-Location -LiteralPath $project

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-Base64File($relativePath, $base64Content) {
  $target = Join-Path $project $relativePath
  $directory = Split-Path $target -Parent

  if (!(Test-Path -LiteralPath $directory)) {
    New-Item -ItemType Directory -Force -Path $directory | Out-Null
  }

  $bytes = [System.Convert]::FromBase64String($base64Content.Trim())
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)

  [System.IO.File]::WriteAllText($target, $content, $utf8NoBom)
  Write-Host "Criado/atualizado: $relativePath" -ForegroundColor Green
}

Write-Base64File "app\painel\financeiro\page.tsx" @"

"@

# Tenta adicionar o botao Financeiro no painel principal sem quebrar o JSX.
$painel = Join-Path $project "app\painel\page.tsx"

if (Test-Path -LiteralPath $painel) {
  $content = [System.IO.File]::ReadAllText($painel)

  if ($content -notmatch "/painel/financeiro") {
    $link = @'

      <a
        href="/painel/financeiro"
        className="rounded-2xl border border-blue-100 bg-white px-4 py-3 text-sm font-black text-[#05245c] transition hover:bg-blue-50"
      >
        Financeiro
      </a>
'@

    if ($content -match "</header>") {
      $content = $content.Replace("</header>", "$link`n</header>")
      [System.IO.File]::WriteAllText($painel, $content, $utf8NoBom)
      Write-Host "Link Financeiro adicionado ao app\painel\page.tsx" -ForegroundColor Green
    } else {
      Write-Host "Nao encontrei </header> no painel. Pagina financeiro criada, mas o botao nao foi inserido automaticamente." -ForegroundColor Yellow
    }
  } else {
    Write-Host "Link Financeiro ja existe no painel." -ForegroundColor Cyan
  }
} else {
  Write-Host "app\painel\page.tsx nao encontrado. Pagina financeiro criada mesmo assim." -ForegroundColor Yellow
}

Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "Financeiro instalado em: app\painel\financeiro\page.tsx" -ForegroundColor Green
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
Write-Host ""
